dashboard_theme <- bs_theme(
  version = 5,
  bg = "#F5EFE6",
  fg = "#22313F",
  primary = "#0A6762",
  secondary = "#C96A43",
  success = "#0B5F59",
  warning = "#D89A2B",
  danger = "#BE4C3A",
  base_font = font_collection(font_google("IBM Plex Sans"), "Segoe UI", "sans-serif"),
  heading_font = font_collection(font_google("Fraunces"), "Georgia", "serif")
)

app_header <- tags$head(
  tags$style(HTML("\n    :root {\n      --sand: #f5efe6;\n      --paper: rgba(255, 252, 247, 0.92);\n      --ink: #22313f;\n      --teal: #0a6762;\n      --coral: #c96a43;\n      --gold: #d89a2b;\n      --line: rgba(34, 49, 63, 0.12);\n      --muted: #62707b;\n    }\n    body {\n      background: radial-gradient(circle at top right, rgba(216,154,43,0.18), transparent 26%), linear-gradient(180deg, #f3ece2 0%, #f8f3ec 44%, #f1ebe1 100%);\n    }\n    .navbar {\n      backdrop-filter: blur(8px);\n      background: rgba(245, 239, 230, 0.9) !important;\n      border-bottom: 1px solid var(--line);\n    }\n    .navbar-nav .nav-link {\n      border-radius: 999px;\n      margin: 0 0.15rem;\n      padding: 0.45rem 0.9rem;\n      color: #41505c;\n    }\n    .navbar-nav .nav-link.active {\n      background: rgba(10,103,98,0.1);\n      color: var(--teal);\n      font-weight: 600;\n    }\n    .app-title-wrap {\n      display: flex;\n      flex-direction: column;\n      gap: 0.05rem;\n    }\n    .app-kicker {\n      font-size: 0.72rem;\n      letter-spacing: 0.12em;\n      text-transform: uppercase;\n      color: #5f6d79;\n    }\n    .app-title {\n      font-size: 1.1rem;\n      font-weight: 700;\n    }\n    .bslib-page-fill {\n      gap: 1.1rem;\n    }\n    .hero-card {\n      background: linear-gradient(135deg, rgba(10,103,98,0.98), rgba(104,126,64,0.92));\n      color: white;\n      border: none;\n      box-shadow: 0 22px 50px rgba(34, 49, 63, 0.14);\n    }\n    .hero-card .card-body {\n      padding: 1.5rem 1.5rem 1.35rem 1.5rem;\n    }\n    .hero-card h2,\n    .hero-card p,\n    .hero-card div {\n      position: relative;\n      z-index: 1;\n      color: rgba(255,255,255,0.96);\n    }\n    .metric-note {\n      font-size: 0.92rem;\n      color: #4a5563;\n    }\n    .card {\n      border: 1px solid rgba(34,49,63,0.08);\n      box-shadow: 0 12px 24px rgba(34,49,63,0.05);\n      border-radius: 1rem;\n    }\n    .card-header {\n      font-weight: 600;\n      letter-spacing: 0.01em;\n      background: rgba(255, 252, 247, 0.72);\n      border-bottom: 1px solid rgba(34,49,63,0.08);\n    }\n    .sidebar {\n      background: rgba(255, 252, 247, 0.72);\n      border-right: 1px solid rgba(34,49,63,0.08);\n      backdrop-filter: blur(6px);\n    }\n    .value-box {\n      border-radius: 1rem;\n      box-shadow: 0 10px 24px rgba(34,49,63,0.06);\n    }\n    .kpi-box {\n      overflow: hidden;\n      position: relative;\n      border: 1px solid rgba(34,49,63,0.06);\n      box-shadow: 0 16px 30px rgba(34,49,63,0.08);\n    }\n    .kpi-box::after {\n      content: \"\";\n      position: absolute;\n      inset: auto -18% -35% auto;\n      width: 130px;\n      height: 130px;\n      border-radius: 999px;\n      background: rgba(255,255,255,0.14);\n      pointer-events: none;\n    }\n    .kpi-box .value-box-title {\n      text-transform: uppercase;\n      letter-spacing: 0.08em;\n      font-size: 0.72rem;\n      font-weight: 700;\n      opacity: 0.9;\n    }\n    .kpi-box .value-box-title,\n    .kpi-box .value-box-value,\n    .kpi-box .value-box-showcase,\n    .kpi-box .value-box-area p,\n    .kpi-box p {\n      color: rgba(255,255,255,0.97) !important;\n      position: relative;\n      z-index: 1;\n      text-shadow: 0 1px 1px rgba(0,0,0,0.08);\n    }\n    .value-box .value-box-value {\n      font-size: 1.7rem;\n      line-height: 1.05;\n    }\n    .kpi-box .value-box-value {\n      margin-top: 0.2rem;\n      margin-bottom: 0.35rem;\n    }\n    .kpi-box p {\n      margin-bottom: 0;\n      font-size: 0.88rem;\n      line-height: 1.45;\n      opacity: 0.92;\n    }\n    .kpi-emerald {\n      background: linear-gradient(135deg, #0a6762, #2d8b81);\n      color: white;\n    }\n    .kpi-amber {\n      background: linear-gradient(135deg, #b87d1f, #d8a03a);\n      color: white;\n    }\n    .kpi-coral {\n      background: linear-gradient(135deg, #b85738, #d77c56);\n      color: white;\n    }\n    .kpi-slate {\n      background: linear-gradient(135deg, #2b3e4a, #48616e);\n      color: white;\n    }\n    .section-copy {\n      font-size: 0.96rem;\n      line-height: 1.65;\n      color: #33424f;\n    }\n    .section-copy.compact {\n      font-size: 0.9rem;\n      line-height: 1.55;\n      color: var(--muted);\n      margin-bottom: 0;\n    }\n    .caption-chip {\n      display: inline-block;\n      padding: 0.25rem 0.6rem;\n      border-radius: 999px;\n      background: rgba(255,255,255,0.14);\n      border: 1px solid rgba(255,255,255,0.18);\n      color: rgba(255,255,255,0.95);\n      font-size: 0.84rem;\n      margin-bottom: 0.5rem;\n    }\n    .hero-lead {\n      max-width: 56rem;\n      font-size: 1rem;\n      line-height: 1.7;\n      color: rgba(255,255,255,0.9);\n      margin-bottom: 0.9rem;\n    }\n    .hero-strip {\n      display: flex;\n      flex-wrap: wrap;\n      gap: 0.55rem;\n      margin-top: 0.25rem;\n    }\n    .hero-pill {\n      padding: 0.42rem 0.8rem;\n      border-radius: 999px;\n      background: rgba(255,255,255,0.14);\n      border: 1px solid rgba(255,255,255,0.18);\n      font-size: 0.83rem;\n      letter-spacing: 0.01em;\n    }\n    .control-note {\n      padding: 0.8rem 0.9rem;\n      border-radius: 0.9rem;\n      background: rgba(10,103,98,0.07);\n      border: 1px solid rgba(10,103,98,0.12);\n      color: #29434f;\n      font-size: 0.88rem;\n      line-height: 1.55;\n    }\n    .control-note strong {\n      color: var(--teal);\n    }\n    .overview-note-card {\n      background: rgba(255, 252, 247, 0.82);\n      border: 1px solid rgba(34,49,63,0.08);\n    }\n    .overview-note-card .card-body {\n      padding: 1.25rem 1.25rem 1.15rem 1.25rem;\n    }\n    .mini-kicker {\n      display: inline-block;\n      margin-bottom: 0.6rem;\n      color: var(--teal);\n      font-size: 0.76rem;\n      font-weight: 700;\n      letter-spacing: 0.08em;\n      text-transform: uppercase;\n    }\n    .metric-grid-copy {\n      color: var(--muted);\n      font-size: 0.9rem;\n      line-height: 1.55;\n      margin-bottom: 0.75rem;\n    }\n    .insight-list {\n      margin-bottom: 0;\n      padding-left: 1.15rem;\n      color: #33424f;\n    }\n    .insight-list li {\n      margin-bottom: 0.45rem;\n    }\n    .definition-list {\n      display: grid;\n      grid-template-columns: minmax(0, 180px) minmax(0, 1fr);\n      gap: 0.65rem 1rem;\n      margin: 0;\n    }\n    .definition-list dt {\n      color: #22313f;\n      font-weight: 600;\n      margin: 0;\n    }\n    .definition-list dd {\n      color: var(--muted);\n      margin: 0;\n      line-height: 1.55;\n    }\n    .source-list {\n      margin: 0;\n      padding-left: 1.1rem;\n      color: var(--muted);\n    }\n    .source-list li {\n      margin-bottom: 0.4rem;\n    }\n  "))
)

